                    col_name = col_name.strip().lower()
                    if col_name in ('compound', 'lower', 'upper'):
                        col_map[col_name] = i

                # Validate we have all required columns
                if 'compound' not in col_map or 'lower' not in col_map or 'upper' not in col_map:
                    raise ParseError("TSV header must contain 'compound', 'lower', and 'upper' columns")

                for line in f:
                    parts = line.strip().split('\t')
                    if len(parts) != 3:
